<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Conway's Game of Life</title>
<style>
  html,body{
    height:100%;
    margin:0;
    background:#111;
    color:#eee;
    font-family:sans-serif;
    display:flex;
    align-items:center;
    justify-content:center;
    flex-direction:column;
  }
  #container{
    text-align:center;
  }
  canvas{
    background:#222;
    display:block;
    margin:0 auto 10px;
    border:2px solid #555;
    cursor:crosshair;
  }
  button{
    background:#333;
    color:#eee;
    border:1px solid #555;
    padding:6px 12px;
    margin:2px;
    cursor:pointer;
    font-size:14px;
  }
  button:hover{
    background:#444;
  }
</style>
</head>
<body>
<div id="container">
  <canvas id="life" width="500" height="500"></canvas>
  <div>
    <button id="step">Step</button>
    <button id="play">Play</button>
    <button id="random">Random</button>
    <button id="clear">Clear</button>
  </div>
</div>

<script>
(() => {
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');

  // grid dimensions (cells)
  const w = 80;   // >=40
  const h = 80;   // >=40
  const cellSize = canvas.width / w;

  // internal grid
  let grid = new Uint8Array(w * h);
  let running = false;
  let intervalId = null;

  // ---------- Rendering ----------
  function draw() {
    ctx.fillStyle = '#222';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = '#0f0';
    for (let y = 0; y < h; y++) {
      for (let x = 0; x < w; x++) {
        if (grid[y * w + x]) {
          ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
        }
      }
    }
  }

  // ---------- API ----------
  window.life = {
    w, h,
    get(x, y) {
      if (x < 0 || y < 0 || x >= w || y >= h) return 0;
      return grid[y * w + x];
    },
    set(x, y, v) {
      if (x < 0 || y < 0 || x >= w || y >= h) return;
      grid[y * w + x] = v ? 1 : 0;
      draw();
    },
    step() {
      const next = new Uint8Array(w * h);
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          let live = grid[y * w + x];
          let neighbours = 0;
          for (let dy = -1; dy <= 1; dy++) {
            for (let dx = -1; dx <= 1; dx++) {
              if (dx === 0 && dy === 0) continue;
              const nx = x + dx;
              const ny = y + dy;
              if (nx >= 0 && ny >= 0 && nx < w && ny < h) {
                neighbours += grid[ny * w + nx];
              }
            }
          }
          // B3/S23
          if (live) {
            next[y * w + x] = (neighbours === 2 || neighbours === 3) ? 1 : 0;
          } else {
            next[y * w + x] = (neighbours === 3) ? 1 : 0;
          }
        }
      }
      grid = next;
      draw();
    },
    clear() {
      grid.fill(0);
      draw();
    }
  };

  // ---------- Controls ----------
  document.getElementById('step').addEventListener('click', () => {
    window.life.step();
  });

  document.getElementById('play').addEventListener('click', (e) => {
    running = !running;
    e.target.textContent = running ? 'Pause' : 'Play';
    if (running) {
      intervalId = setInterval(() => window.life.step(), 200);
    } else {
      clearInterval(intervalId);
    }
  });

  document.getElementById('random').addEventListener('click', () => {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.3 ? 1 : 0;
    }
    draw();
  });

  document.getElementById('clear').addEventListener('click', () => {
    window.life.clear();
  });

  // ---------- Mouse interaction ----------
  let isDrawing = false;
  let drawValue = 1; // what value we are painting while dragging

  function getCellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX - rect.left) / cellSize);
    const y = Math.floor((e.clientY - rect.top) / cellSize);
    return {x, y};
  }

  canvas.addEventListener('pointerdown', (e) => {
    e.preventDefault();
    const {x, y} = getCellFromEvent(e);
    if (x < 0 || y < 0 || x >= w || y >= h) return;
    const idx = y * w + x;
    drawValue = grid[idx] ? 0 : 1; // toggle
    grid[idx] = drawValue;
    draw();
    isDrawing = true;
  });

  canvas.addEventListener('pointermove', (e) => {
    if (!isDrawing) return;
    const {x, y} = getCellFromEvent(e);
    if (x < 0 || y < 0 || x >= w || y >= h) return;
    const idx = y * w + x;
    if (grid[idx] !== drawValue) {
      grid[idx] = drawValue;
      draw();
    }
  });

  canvas.addEventListener('pointerup', () => { isDrawing = false; });
  canvas.addEventListener('pointerleave', () => { isDrawing = false; });

  // Initial draw
  draw();
})();
</script>
</body>
</html>
